record.field:
# Navigate: invoice -> invoice lines -> sale order lines -> sale order -> saas_subscription_id
subscription = False
for line in record.invoice_line_ids:
	for sale_line in line.sale_line_ids:
		if sale_line.order_id and sale_line.order_id.saas_subscription_id:
			subscription = sale_line.order_id.saas_subscription_id
			break
	if subscription:
		break

# Guard: prevent duplicate send across multiple invoices for the same transaction.
if subscription and not subscription.payment_email_sent and record.partner_id.email:
	template = env.ref(
		'saas_provisioning.email_template_saas_invoice_payment_confirmation',
		raise_if_not_found=False
	)
	if template:
		template.send_mail(record.id, force_send=True)
		record.message_post(
			body="System: SaaS payment confirmation email sent to %s." % record.partner_id.email
		)
		# Write True to subscription so subsequent invoices don't trigger it again
		subscription.write({
			'payment_email_sent': True
		})
